import org.springframework.stereotype.Component;
import javax.crypto.BadPaddingException;
import javax.crypto.Cipher;
import javax.crypto.IllegalBlockSizeException;
import javax.crypto.NoSuchPaddingException;
import java.security.InvalidKeyException;
import java.security.KeyFactory;
import java.security.NoSuchAlgorithmException;
import java.security.PublicKey;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.X509EncodedKeySpec;
import java.util.Base64;
@Component
public class RSAUtil {
  protected static String DEFAULT_ENCRYPTION_ALGORITHM = "RSA";
  protected static String DEFAULT_TRANSFORMATION = "RSA/ECB/PKCS1Padding";
  public static PublicKey getPublicKey(String base64PublicKey) {
    PublicKey publicKey = null;
    try {
      X509EncodedKeySpec keySpec = new 
X509EncodedKeySpec(Base64.getDecoder().decode(base64PublicKey.getBytes()));
      KeyFactory keyFactory = 
KeyFactory.getInstance(DEFAULT_ENCRYPTION_ALGORITHM);
      publicKey = keyFactory.generatePublic(keySpec);
      return publicKey;
    } catch (NoSuchAlgorithmException e) {
      e.printStackTrace();
    } catch (InvalidKeySpecException e) {
      e.printStackTrace();
    }
    return publicKey;
  }
  public static String encrypt(String data, String publicKey) throws 
BadPaddingException, IllegalBlockSizeException,
      InvalidKeyException, NoSuchPaddingException, NoSuchAlgorithmException {
    Cipher cipher = Cipher.getInstance(DEFAULT_TRANSFORMATION);
    cipher.init(Cipher.ENCRYPT_MODE, getPublicKey(publicKey));
    return Base64.getEncoder().encodeToString(cipher.doFinal(data.getBytes()));
  }
  public static void main(String[] args) throws NoSuchAlgorithmException,
      InvalidKeyException, BadPaddingException, IllegalBlockSizeException,
NoSuchPaddingException {
    String publicKey = ""; // public key provided to encrypt data
    String encryptData = RSAUtil.encrypt("TEST", publicKey);
    System.out.println("Encrypted String-" + encryptData);
  }
}

